window.FUNGAL_QUESTIONS.push(...[{"id":"Q051","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Easy","source":"PDF p. 56","question":{"en":"Which test should be used to confirm onychomycosis before prolonged systemic treatment?","ar":"أي اختبار يجب استخدامه لتأكيد فطار الأظافر قبل علاج جهازي طويل؟"},"options":[{"letter":"A","en":"KOH microscopy, fungal culture, or PAS stain","ar":"فحص KOH أو المزرعة الفطرية أو صبغة PAS"},{"letter":"B","en":"Serum sodium only","ar":"صوديوم المصل فقط"},{"letter":"C","en":"Skin prick testing","ar":"اختبار وخز الجلد"},{"letter":"D","en":"Chest radiography","ar":"أشعة الصدر"}],"correct":"A","explanation":{"en":"Many nail disorders mimic fungal disease, so mycologic confirmation is recommended before systemic therapy.","ar":"تشبه اضطرابات أظافر كثيرة العدوى الفطرية، لذلك يوصى بالتأكيد الفطري قبل العلاج الجهازي."},"reasoning":{"en":"The long duration, interactions, and potential toxicity make empiric oral therapy inappropriate without confirmation.","ar":"طول مدة العلاج والتداخلات والسمية المحتملة تجعل العلاج الفموي التجريبي غير مناسب دون تأكيد."},"image":null},{"id":"Q052","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Easy","source":"PDF p. 59","question":{"en":"Which oral agent is generally preferred for dermatophyte onychomycosis?","ar":"أي دواء فموي يُفضل عادةً لفطار الأظافر الناتج عن الفطريات الجلدية؟"},"options":[{"letter":"A","en":"Terbinafine","ar":"تيربينافين"},{"letter":"B","en":"Nystatin","ar":"نيستاتين"},{"letter":"C","en":"Oral ketoconazole","ar":"كيتوكونازول فموي"},{"letter":"D","en":"Selenium sulfide","ar":"سيلينيوم سلفايد"}],"correct":"A","explanation":{"en":"Oral terbinafine is the preferred therapy for most dermatophyte nail infections.","ar":"التيربينافين الفموي هو العلاج المفضل لمعظم عدوى الأظافر بالفطريات الجلدية."},"reasoning":{"en":"Its dermatophyte activity and nail penetration make it more effective than topical-only therapy in significant disease.","ar":"فعاليته ضد الفطريات الجلدية واختراقه للظفر يجعلان استخدامه أنسب في المرض المهم."},"image":null},{"id":"Q053","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Case","difficulty":"Hard","source":"PDF p. 57","question":{"en":"A great toenail develops yellow-brown discoloration beginning at the distal-lateral edge, subungual debris, and onycholysis. What subtype is most likely?","ar":"بدأ ظفر إصبع القدم الكبير بلون أصفر بني من الحافة البعيدة الجانبية مع حطام تحت الظفر وانفصال الصفيحة. ما النوع الأرجح؟"},"options":[{"letter":"A","en":"DLSO","ar":"فطار تحت الظفر البعيد الجانبي"},{"letter":"B","en":"PSO","ar":"فطار تحت الظفر القريب"},{"letter":"C","en":"Endonyx","ar":"فطار داخل الصفيحة"},{"letter":"D","en":"Acute paronychia","ar":"التهاب حاد حول الظفر"}],"correct":"A","explanation":{"en":"Distal-lateral onset with subungual hyperkeratosis and onycholysis is classic DLSO.","ar":"البداية البعيدة الجانبية مع فرط تقرن تحت الظفر وانفصال الصفيحة نمط كلاسيكي لـ DLSO."},"reasoning":{"en":"Both the entry point and the accompanying nail-bed changes support the subtype.","ar":"نقطة البداية والتغيرات المصاحبة في سرير الظفر تدعمان هذا النوع."},"image":null},{"id":"Q054","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Case","difficulty":"Medium","source":"PDF p. 57","question":{"en":"A nail has soft, dull white patches confined to the surface and easily removed with scraping. Which subtype is present?","ar":"يوجد بالظفر بقع بيضاء باهتة رخوة سطحية يمكن إزالتها بالكشط بسهولة. ما النوع؟"},"options":[{"letter":"A","en":"White superficial onychomycosis","ar":"فطار الأظافر الأبيض السطحي"},{"letter":"B","en":"Total dystrophic onychomycosis","ar":"فطار الأظافر الضموري الكلي"},{"letter":"C","en":"DLSO","ar":"فطار تحت الظفر البعيد الجانبي"},{"letter":"D","en":"Fungal melanonychia","ar":"التصبغ الفطري للظفر"}],"correct":"A","explanation":{"en":"The superficial, chalky, scrapable appearance is diagnostic of WSO.","ar":"المظهر السطحي الطباشيري القابل للكشط يميز WSO."},"reasoning":{"en":"The lesion is in the dorsal plate rather than beneath it.","ar":"تقع الآفة في سطح الصفيحة وليس تحتها."},"image":null},{"id":"Q055","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Case","difficulty":"Medium","source":"PDF p. 57","question":{"en":"An adult with advanced HIV develops white discoloration beginning at the proximal nail fold and extending distally. What is the most likely subtype?","ar":"بالغ مصاب بـ HIV متقدم لديه تغير أبيض يبدأ من ثنية الظفر القريبة ويمتد بعيدًا. ما النوع الأرجح؟"},"options":[{"letter":"A","en":"Proximal subungual onychomycosis","ar":"فطار الأظافر تحت الظفر القريب"},{"letter":"B","en":"DLSO","ar":"فطار تحت الظفر البعيد الجانبي"},{"letter":"C","en":"WSO","ar":"فطار الأظافر الأبيض السطحي"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"Proximal onset is characteristic of PSO and has a strong association with immunosuppression.","ar":"البداية القريبة تميز PSO وترتبط بقوة بضعف المناعة."},"reasoning":{"en":"The host factor and direction of spread are mutually reinforcing clues.","ar":"عامل العائل واتجاه الانتشار دليلان يدعم كل منهما الآخر."},"image":null},{"id":"Q056","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Case","difficulty":"Medium","source":"PDF p. 57","question":{"en":"A nail is discolored and split, but there is no onycholysis or subungual hyperkeratosis. Infection appears confined within the plate. Which subtype fits best?","ar":"الظفر متغير اللون ومتشقّق دون انفصال أو فرط تقرن تحته، وتبدو العدوى داخل الصفيحة فقط. أي نوع يناسب أكثر؟"},"options":[{"letter":"A","en":"Endonyx onychomycosis","ar":"فطار الأظافر داخل الصفيحة"},{"letter":"B","en":"DLSO","ar":"فطار تحت الظفر البعيد الجانبي"},{"letter":"C","en":"PSO","ar":"فطار تحت الظفر القريب"},{"letter":"D","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"}],"correct":"A","explanation":{"en":"Endonyx disease affects the interior of the plate without nail-bed involvement.","ar":"يصيب Endonyx داخل صفيحة الظفر دون إصابة سرير الظفر."},"reasoning":{"en":"The absence of subungual debris is the key exclusion of common DLSO.","ar":"غياب الحطام تحت الظفر هو المفتاح لاستبعاد DLSO الشائع."},"image":null},{"id":"Q057","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Case","difficulty":"Medium","source":"PDF p. 58","question":{"en":"A patient has a linear yellow-orange streak within an infected nail and has failed standard oral therapy. What finding may explain the resistance?","ar":"مريض لديه خط أصفر برتقالي داخل ظفر مصاب ولم يستجب للعلاج الفموي المعتاد. ما العلامة التي قد تفسر المقاومة؟"},"options":[{"letter":"A","en":"Dermatophytoma","ar":"Dermatophytoma"},{"letter":"B","en":"Koilonychia","ar":"تقعر الظفر"},{"letter":"C","en":"Leukonychia from trauma","ar":"ابيضاض الظفر بسبب صدمة"},{"letter":"D","en":"Subungual hematoma only","ar":"ورم دموي تحت الظفر فقط"}],"correct":"A","explanation":{"en":"A compact fungal mass can appear as a colored streak and is associated with poor response because drug penetration is limited.","ar":"قد تظهر الكتلة الفطرية المدمجة كشريط ملون وترتبط بضعف الاستجابة بسبب محدودية اختراق الدواء."},"reasoning":{"en":"Morphology plus treatment failure suggests a high-density fungal focus.","ar":"الشكل مع فشل العلاج يشيران إلى بؤرة فطرية عالية الكثافة."},"image":null},{"id":"Q058","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Case","difficulty":"Hard","source":"PDF p. 58","question":{"en":"A diabetic patient with toenail onychomycosis has chronic edema and two previous episodes of cellulitis in the same leg. Why is treatment particularly important?","ar":"مريض سكري لديه فطار أظافر القدم ووذمة مزمنة ونوبتان سابقتان من التهاب النسيج الخلوي بنفس الساق. لماذا العلاج مهم خصوصًا؟"},"options":[{"letter":"A","en":"The infected nail can contribute to recurrent bacterial cellulitis","ar":"قد يساهم الظفر المصاب في تكرار التهاب النسيج الخلوي البكتيري"},{"letter":"B","en":"It always causes systemic candidemia","ar":"يسبب دائمًا كانديديميا جهازية"},{"letter":"C","en":"It prevents all nail growth permanently","ar":"يمنع نمو الظفر دائمًا"},{"letter":"D","en":"It directly causes hypertension","ar":"يسبب ارتفاع الضغط مباشرة"}],"correct":"A","explanation":{"en":"Onychomycosis and associated skin barrier disruption can act as portals or reservoirs in high-risk legs.","ar":"قد يعمل فطار الأظافر واضطراب الحاجز الجلدي المصاحب كبوابة أو مستودع في الأطراف عالية الخطورة."},"reasoning":{"en":"The risk-benefit threshold for treatment is lower when there is a history of recurrent cellulitis.","ar":"تزداد أهمية العلاج عندما توجد سوابق التهاب نسيج خلوي متكرر."},"image":null},{"id":"Q059","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Case","difficulty":"Hard","source":"PDF p. 58","question":{"en":"A black longitudinal nail band is presumed fungal, but the diagnosis is uncertain. What is the safest next step?","ar":"اعتُبر خط أسود طولي بالظفر فطريًا لكن التشخيص غير مؤكد. ما الخطوة الأكثر أمانًا؟"},"options":[{"letter":"A","en":"Evaluate for melanocytic disease and confirm fungal etiology","ar":"تقييم الأمراض الميلانينية وتأكيد السبب الفطري"},{"letter":"B","en":"Assume all dark bands are onychomycosis","ar":"اعتبار كل الخطوط الداكنة فطار أظافر"},{"letter":"C","en":"Use steroid cream only","ar":"استخدام كورتيزون فقط"},{"letter":"D","en":"Ignore progression","ar":"تجاهل التطور"}],"correct":"A","explanation":{"en":"Fungal melanonychia can mimic melanocytic lesions; potentially serious alternatives must be excluded.","ar":"يمكن للتصبغ الفطري بالظفر أن يشبه الآفات الميلانينية، لذلك يجب استبعاد البدائل المهمة."},"reasoning":{"en":"Pigmentation is not specific; diagnostic safety requires ruling out melanoma before routine antifungal treatment.","ar":"التصبغ غير نوعي؛ والأمان التشخيصي يتطلب استبعاد الميلانوما قبل العلاج الروتيني."},"image":null},{"id":"Q060","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Treatment","difficulty":"Medium","source":"PDF p. 59","question":{"en":"A patient has dermatophyte onychomycosis affecting more than 50% of the nail with matrix involvement. What is the preferred approach?","ar":"مريض لديه فطار أظافر جلدي يصيب أكثر من 50% من الظفر مع إصابة المصفوفة. ما النهج المفضل؟"},"options":[{"letter":"A","en":"Oral terbinafine","ar":"تيربينافين فموي"},{"letter":"B","en":"Topical powder alone","ar":"بودرة موضعية فقط"},{"letter":"C","en":"Nystatin mouth rinse","ar":"مضمضة نيستاتين"},{"letter":"D","en":"Selenium sulfide shampoo","ar":"شامبو سيلينيوم سلفايد"}],"correct":"A","explanation":{"en":"Matrix involvement and extensive disease reduce the effectiveness of topical monotherapy; oral terbinafine is preferred for dermatophytes.","ar":"إصابة المصفوفة وانتشار المرض يقللان فعالية العلاج الموضعي وحده، ويُفضل التيربينافين الفموي للفطريات الجلدية."},"reasoning":{"en":"Depth and extent determine the need for systemic nail-penetrating therapy.","ar":"عمق الإصابة وانتشارها يحددان الحاجة إلى علاج جهازي يخترق الظفر."},"image":null},{"id":"Q061","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Treatment","difficulty":"Hard","source":"PDF p. 59","question":{"en":"Confirmed yeast or non-dermatophyte mold onychomycosis is present. Which oral agent is generally preferred in the chapter?","ar":"تم تأكيد فطار أظافر بخميرة أو عفن غير جلدي. أي دواء فموي يُفضل عادةً في الفصل؟"},"options":[{"letter":"A","en":"Itraconazole","ar":"إيتراكونازول"},{"letter":"B","en":"Penicillin V","ar":"بنسلين V"},{"letter":"C","en":"Topical mupirocin","ar":"ميوبيروسين موضعي"},{"letter":"D","en":"Oral griseofulvin for one day","ar":"جريزوفولفين فموي ليوم واحد"}],"correct":"A","explanation":{"en":"Itraconazole has broader activity and is preferred for many yeast and non-dermatophyte mold nail infections.","ar":"يمتلك الإيتراكونازول طيفًا أوسع ويُفضل في كثير من عدوى الأظافر بالخمائر والعفن غير الجلدي."},"reasoning":{"en":"Species identification matters because the optimal systemic agent changes with the pathogen group.","ar":"تحديد النوع مهم لأن الدواء الجهازي الأمثل يتغير حسب مجموعة الممرض."},"image":null},{"id":"Q062","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Treatment","difficulty":"Easy","source":"PDF p. 59","question":{"en":"When is topical nail lacquer most reasonable?","ar":"متى يكون طلاء الظفر المضاد للفطريات خيارًا منطقيًا؟"},"options":[{"letter":"A","en":"Mild superficial disease without matrix involvement or when oral therapy is unsuitable","ar":"مرض سطحي بسيط دون إصابة المصفوفة أو عند تعذر العلاج الفموي"},{"letter":"B","en":"Total nail destruction with matrix disease","ar":"تدمير كامل للظفر مع إصابة المصفوفة"},{"letter":"C","en":"Rapidly spreading cellulitis","ar":"التهاب نسيج خلوي سريع الانتشار"},{"letter":"D","en":"Kerion of the scalp","ar":"كيريون فروة الرأس"}],"correct":"A","explanation":{"en":"Topical treatments are safest but require prolonged use and have lower efficacy when the matrix is involved.","ar":"العلاجات الموضعية أكثر أمانًا لكنها تحتاج مدة طويلة وتقل فعاليتها عند إصابة المصفوفة."},"reasoning":{"en":"Topical penetration is adequate only for limited accessible nail disease.","ar":"يكون اختراق العلاج الموضعي كافيًا فقط في المرض المحدود القابل للوصول."},"image":null},{"id":"Q063","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Treatment","difficulty":"Hard","source":"PDF p. 59","question":{"en":"A severely deformed refractory nail is surgically avulsed. What should follow to reduce recurrence?","ar":"تم خلع ظفر شديد التشوه ومقاوم جراحيًا. ماذا يجب أن يتبع ذلك لتقليل التكرار؟"},"options":[{"letter":"A","en":"Continue appropriate topical or systemic antifungal therapy","ar":"استمرار علاج فطري موضعي أو جهازي مناسب"},{"letter":"B","en":"No further treatment is needed","ar":"لا حاجة لأي علاج آخر"},{"letter":"C","en":"Use antibiotics indefinitely","ar":"استخدام مضاد حيوي دائمًا"},{"letter":"D","en":"Apply potent steroid under occlusion","ar":"وضع كورتيزون قوي تحت غطاء"}],"correct":"A","explanation":{"en":"Avulsion removes diseased nail material but does not reliably eradicate residual fungi; antifungal therapy is needed.","ar":"يزيل الخلع مادة الظفر المصابة لكنه لا يقضي بشكل موثوق على الفطر المتبقي، لذا يلزم علاج مضاد للفطريات."},"reasoning":{"en":"Mechanical removal without microbiologic eradication leaves a high recurrence risk.","ar":"الإزالة الميكانيكية دون القضاء على الفطر تترك خطر تكرار مرتفعًا."},"image":null},{"id":"Q064","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Image","difficulty":"Medium","source":"PDF p. 60","question":{"en":"The image shows chalky white patches on the superficial nail plate. Which subtype is most likely?","ar":"توضح الصورة بقعًا بيضاء طباشيرية على سطح صفيحة الظفر. ما النوع الأرجح؟"},"options":[{"letter":"A","en":"White superficial onychomycosis","ar":"فطار الأظافر الأبيض السطحي"},{"letter":"B","en":"DLSO","ar":"فطار تحت الظفر البعيد الجانبي"},{"letter":"C","en":"PSO","ar":"فطار تحت الظفر القريب"},{"letter":"D","en":"Acute bacterial paronychia","ar":"التهاب بكتيري حاد حول الظفر"}],"correct":"A","explanation":{"en":"The visible superficial white material is typical of WSO.","ar":"المادة البيضاء السطحية الظاهرة نموذجية لـ WSO."},"reasoning":{"en":"The abnormality is on top of the plate rather than starting beneath it.","ar":"يظهر التغير فوق صفيحة الظفر وليس من تحتها."},"image":"assets/images/chapters/fungal/fungal-q064.webp"},{"id":"Q065","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Image","difficulty":"Hard","source":"PDF p. 60","question":{"en":"The image shows discoloration beginning near the proximal nail fold. Which subtype should be considered?","ar":"توضح الصورة تغيرًا يبدأ قرب ثنية الظفر القريبة. أي نوع يجب التفكير فيه؟"},"options":[{"letter":"A","en":"Proximal subungual onychomycosis","ar":"فطار الأظافر تحت الظفر القريب"},{"letter":"B","en":"DLSO","ar":"فطار تحت الظفر البعيد الجانبي"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Interdigital candidiasis","ar":"داء المبيضات بين الأصابع"}],"correct":"A","explanation":{"en":"Proximal white or yellow change near the cuticle is the defining visual pattern of PSO.","ar":"التغير الأبيض أو الأصفر القريب من الجلد المحيط هو النمط البصري المميز لـ PSO."},"reasoning":{"en":"The point of origin, not just the color, identifies the subtype.","ar":"نقطة بداية التغير لا اللون وحده هي التي تحدد النوع."},"image":"assets/images/chapters/fungal/fungal-q065.webp"},{"id":"Q066","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"Image","difficulty":"Easy","source":"PDF p. 60","question":{"en":"The image shows severe thickening, deformity, and near-total destruction of the nail plate. What is the stage?","ar":"توضح الصورة سماكة وتشوهًا شديدين مع تدمير شبه كامل لصفيحة الظفر. ما المرحلة؟"},"options":[{"letter":"A","en":"Total dystrophic onychomycosis","ar":"فطار الأظافر الضموري الكلي"},{"letter":"B","en":"Early WSO","ar":"مرحلة مبكرة من WSO"},{"letter":"C","en":"Tinea cruris","ar":"سعفة الأرفاغ"},{"letter":"D","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"}],"correct":"A","explanation":{"en":"Total dystrophic disease is the end stage of long-standing onychomycosis with extensive plate destruction and keratotic debris.","ar":"الفطار الضموري الكلي هو المرحلة النهائية للعدوى المزمنة مع تدمير واسع للصفيحة وحطام كيراتيني."},"reasoning":{"en":"The degree of structural loss distinguishes end-stage disease from limited subtypes.","ar":"درجة فقد البنية تميز المرحلة النهائية عن الأنواع المحدودة."},"image":"assets/images/chapters/fungal/fungal-q066.webp"},{"id":"Q067","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Medium","source":"PDF p. 61","question":{"en":"Which population is most commonly affected by tinea capitis?","ar":"أي فئة تُصاب غالبًا بسعفة الرأس؟"},"options":[{"letter":"A","en":"Prepubertal children","ar":"الأطفال قبل البلوغ"},{"letter":"B","en":"Healthy older adults only","ar":"كبار السن الأصحاء فقط"},{"letter":"C","en":"Newborns exclusively","ar":"حديثو الولادة فقط"},{"letter":"D","en":"Pregnant women exclusively","ar":"الحوامل فقط"}],"correct":"A","explanation":{"en":"Tinea capitis primarily affects children before puberty; adult cases are less common and may be linked to immunosuppression.","ar":"تصيب سعفة الرأس أساسًا الأطفال قبل البلوغ، وتكون أقل شيوعًا في البالغين وقد ترتبط بضعف المناعة."},"reasoning":{"en":"Age is a strong epidemiologic clue when evaluating scaly alopecia.","ar":"العمر دليل وبائي قوي عند تقييم تساقط الشعر المتقشر."},"image":null},{"id":"Q068","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Medium","source":"PDF p. 61","question":{"en":"Which tinea capitis pattern produces broken hairs at scalp level that appear as dark dots?","ar":"أي نمط من سعفة الرأس يسبب تكسر الشعر عند مستوى فروة الرأس وظهوره كنقاط سوداء؟"},"options":[{"letter":"A","en":"Black dot type","ar":"نوع النقاط السوداء"},{"letter":"B","en":"Favus","ar":"الفافوس"},{"letter":"C","en":"Kerion","ar":"الكيريون"},{"letter":"D","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"}],"correct":"A","explanation":{"en":"Infected hairs break at the scalp surface, leaving dark hair stubs within follicles.","ar":"تتكسر الشعيرات المصابة عند سطح فروة الرأس فتترك بقايا داكنة داخل الجريبات."},"reasoning":{"en":"The dots are retained broken shafts, not pigmentation of the skin.","ar":"النقاط هي بقايا ساق شعر مكسورة وليست تصبغًا جلديًا."},"image":null},{"id":"Q069","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Medium","source":"PDF p. 62","question":{"en":"Which tinea capitis form is a boggy, tender inflammatory swelling that may ooze seropurulent material?","ar":"أي شكل من سعفة الرأس يظهر كتورم التهابي إسفنجي مؤلم قد يفرز سائلًا مصليًا صديديًا؟"},"options":[{"letter":"A","en":"Kerion","ar":"الكيريون"},{"letter":"B","en":"Scaly type","ar":"النوع المتقشر"},{"letter":"C","en":"Black dot type","ar":"نوع النقاط السوداء"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"Kerion is a marked inflammatory response, often to zoophilic fungi, and can lead to scarring alopecia if treatment is delayed.","ar":"الكيريون استجابة التهابية شديدة غالبًا لفطريات حيوانية المصدر وقد يؤدي إلى صلع ندبي إذا تأخر العلاج."},"reasoning":{"en":"Boggy inflammation with loose hair is the defining pattern, even when it resembles an abscess.","ar":"التورم الإسفنجي الالتهابي مع سهولة سقوط الشعر هو النمط المميز رغم تشابهه مع الخراج."},"image":null},{"id":"Q070","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Easy","source":"PDF p. 63","question":{"en":"Which finding is characteristic of favus?","ar":"أي علامة تميز الفافوس؟"},"options":[{"letter":"A","en":"Yellow cup-shaped scutula with a mousy odor","ar":"قشور صفراء مقعرة بشكل الكوب مع رائحة تشبه الفأر"},{"letter":"B","en":"Maceration between toes","ar":"تميع بين أصابع القدم"},{"letter":"C","en":"Satellite pustules in a skin fold","ar":"بثور تابعة في ثنية جلدية"},{"letter":"D","en":"Coppery trunk macules","ar":"بقع نحاسية بالجذع"}],"correct":"A","explanation":{"en":"Favus produces yellow concave scutula that may merge into a honeycomb pattern and can cause permanent scarring alopecia.","ar":"يسبب الفافوس قشورًا صفراء مقعرة قد تندمج لتعطي شكل قرص العسل ويمكن أن تسبب صلعًا ندبيًا دائمًا."},"reasoning":{"en":"The distinctive crust morphology and odor separate favus from other scalp types.","ar":"شكل القشور والرائحة المميزان يفصلان الفافوس عن الأنواع الأخرى."},"image":null},{"id":"Q071","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Easy","source":"PDF p. 61","question":{"en":"Which Wood’s lamp finding supports Microsporum tinea capitis?","ar":"أي نتيجة تحت مصباح وود تدعم سعفة الرأس الناتجة عن Microsporum؟"},"options":[{"letter":"A","en":"Green fluorescence","ar":"فلورة خضراء"},{"letter":"B","en":"Coral-red fluorescence","ar":"فلورة حمراء مرجانية"},{"letter":"C","en":"No color in all cases","ar":"لا لون في جميع الحالات"},{"letter":"D","en":"Blue-white fluorescence of bacteria","ar":"فلورة زرقاء بيضاء للبكتيريا"}],"correct":"A","explanation":{"en":"Many Microsporum-infected hairs fluoresce green under Wood’s lamp; common Trichophyton tonsurans infections usually do not.","ar":"تظهر كثير من الشعيرات المصابة بـ Microsporum فلورة خضراء تحت مصباح وود، بينما غالبًا لا تفعل عدوى T. tonsurans."},"reasoning":{"en":"Fluorescence can guide likely species but does not replace microscopy or culture when needed.","ar":"قد تساعد الفلورة في ترجيح النوع لكنها لا تستبدل الفحص المجهري أو المزرعة عند الحاجة."},"image":null},{"id":"Q072","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Easy","source":"PDF p. 61","question":{"en":"Why is topical antifungal therapy alone inadequate for tinea capitis?","ar":"لماذا لا يكفي العلاج الموضعي وحده لسعفة الرأس؟"},"options":[{"letter":"A","en":"It does not adequately penetrate infected hair shafts and follicles","ar":"لا يخترق ساق الشعرة والجريبات المصابة بشكل كافٍ"},{"letter":"B","en":"All topicals are antibacterial only","ar":"كل العلاجات الموضعية مضادات بكتيرية فقط"},{"letter":"C","en":"The disease is always viral","ar":"المرض فيروسي دائمًا"},{"letter":"D","en":"Hair prevents any diagnosis","ar":"الشعر يمنع التشخيص تمامًا"}],"correct":"A","explanation":{"en":"Systemic antifungal therapy is required to reach the infected hair and follicular structures.","ar":"يلزم علاج مضاد فطري جهازي للوصول إلى الشعر والبنى الجريبية المصابة."},"reasoning":{"en":"Anatomic penetration determines the route of therapy.","ar":"اختراق الموقع التشريحي هو ما يحدد طريق العلاج."},"image":null},{"id":"Q073","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Easy","source":"PDF p. 64","question":{"en":"Which organism-treatment pairing is most appropriate?","ar":"أي اقتران بين الكائن والعلاج هو الأنسب؟"},"options":[{"letter":"A","en":"Microsporum canis – griseofulvin preferred","ar":"Microsporum canis – يفضل جريزوفولفين"},{"letter":"B","en":"Trichophyton tonsurans – nystatin preferred","ar":"Trichophyton tonsurans – يفضل نيستاتين"},{"letter":"C","en":"Microsporum canis – topical steroid alone","ar":"Microsporum canis – كورتيزون موضعي وحده"},{"letter":"D","en":"T. tonsurans – selenium shampoo alone","ar":"T. tonsurans – شامبو سيلينيوم وحده"}],"correct":"A","explanation":{"en":"Griseofulvin is particularly effective for Microsporum, whereas terbinafine is often favored for T. tonsurans.","ar":"يكون الجريزوفولفين فعالًا خصوصًا ضد Microsporum، بينما يفضل التيربينافين غالبًا مع T. tonsurans."},"reasoning":{"en":"Species can meaningfully change the best systemic drug choice.","ar":"يمكن لنوع الفطر أن يغير اختيار الدواء الجهازي الأفضل بصورة مهمة."},"image":null},{"id":"Q074","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"MCQ","difficulty":"Easy","source":"PDF p. 64","question":{"en":"Which adjunct reduces shedding and transmission but does not replace oral treatment?","ar":"أي علاج مساعد يقلل تساقط الأبواغ والانتقال لكنه لا يستبدل العلاج الفموي؟"},"options":[{"letter":"A","en":"Selenium sulfide or ketoconazole shampoo","ar":"شامبو سيلينيوم سلفايد أو كيتوكونازول"},{"letter":"B","en":"Topical antibiotic ointment","ar":"مرهم مضاد حيوي موضعي"},{"letter":"C","en":"Emollient only","ar":"مرطب فقط"},{"letter":"D","en":"Oral antihistamine only","ar":"مضاد هيستامين فموي فقط"}],"correct":"A","explanation":{"en":"Antifungal shampoo lowers surface spores and transmission but cannot eradicate infection inside hair shafts.","ar":"يقلل الشامبو المضاد للفطريات الأبواغ السطحية والانتقال لكنه لا يقضي على العدوى داخل ساق الشعرة."},"reasoning":{"en":"Adjunctive surface decontamination complements, rather than replaces, systemic therapy.","ar":"التقليل السطحي للأبواغ يكمل العلاج الجهازي ولا يستبدله."},"image":null},{"id":"Q075","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Case","difficulty":"Medium","source":"PDF p. 62","question":{"en":"A 7-year-old has circular scaly alopecic patches with brittle hairs broken above the scalp and no major inflammation. What is the most likely form?","ar":"طفل 7 سنوات لديه بقع دائرية متقشرة مع فقد شعر وشعيرات هشة مكسورة فوق فروة الرأس دون التهاب شديد. ما الشكل الأرجح؟"},"options":[{"letter":"A","en":"Scaly type tinea capitis","ar":"سعفة الرأس من النوع المتقشر"},{"letter":"B","en":"Kerion","ar":"الكيريون"},{"letter":"C","en":"Favus","ar":"الفافوس"},{"letter":"D","en":"Alopecia areata","ar":"الثعلبة البقعية"}],"correct":"A","explanation":{"en":"The scaly type produces well-defined patches of alopecia with dull, brittle, broken hairs and usually heals without scarring.","ar":"يسبب النوع المتقشر بقع فقد شعر محددة مع شعر باهت هش مكسور، وغالبًا يشفى دون ندبات."},"reasoning":{"en":"Scaling and broken hairs distinguish fungal alopecia from smooth alopecia areata.","ar":"القشور والشعر المكسور يميزان الفقد الفطري عن الثعلبة البقعية الملساء."},"image":null},{"id":"Q076","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Case","difficulty":"Medium","source":"PDF p. 62","question":{"en":"A child has multiple small alopecic patches with hairs broken exactly at scalp level, leaving black stubs. Which diagnosis is most likely?","ar":"طفل لديه بقع صغيرة متعددة من فقد الشعر مع تكسر الشعر عند مستوى الفروة وترك بقايا سوداء. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Black dot tinea capitis","ar":"سعفة الرأس بنمط النقاط السوداء"},{"letter":"B","en":"Vitiligo","ar":"البهاق"},{"letter":"C","en":"Tinea versicolor","ar":"النخالية المبرقشة"},{"letter":"D","en":"Trichotillomania without infection","ar":"هوس نتف الشعر دون عدوى"}],"correct":"A","explanation":{"en":"The black dots are infected hairs that have broken at the scalp surface.","ar":"النقاط السوداء هي شعيرات مصابة انكسرت عند سطح فروة الرأس."},"reasoning":{"en":"The uniform follicular stubs are characteristic of this endothrix pattern.","ar":"البقايا الجريبية الموحدة تميز هذا النمط داخل الشعرة."},"image":null},{"id":"Q077","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Case","difficulty":"Medium","source":"PDF p. 62","question":{"en":"A child exposed to a farm animal develops a tender boggy scalp mass with patchy hair loss and oozing follicles but no true fluctuation. What is most likely?","ar":"طفل تعرض لحيوان مزرعة وظهر لديه تورم إسفنجي مؤلم بفروة الرأس مع فقد شعر وإفرازات من الجريبات دون تذبذب حقيقي. ما الأرجح؟"},"options":[{"letter":"A","en":"Kerion","ar":"الكيريون"},{"letter":"B","en":"Bacterial abscess","ar":"خراج بكتيري"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Seborrheic dermatitis","ar":"التهاب الجلد الدهني"}],"correct":"A","explanation":{"en":"Animal exposure, alopecia, follicular oozing, and boggy nonfluctuant inflammation favor kerion over an abscess.","ar":"التعرض لحيوان وفقد الشعر والإفرازات الجريبية والتورم الإسفنجي غير المتذبذب ترجح الكيريون على الخراج."},"reasoning":{"en":"A true bacterial abscess is usually fluctuant and lacks the characteristic fungal alopecia pattern.","ar":"الخراج البكتيري الحقيقي يكون غالبًا متذبذبًا ولا يصاحبه نمط فقد الشعر الفطري المميز."},"image":null},{"id":"Q078","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Case","difficulty":"Medium","source":"PDF p. 63","question":{"en":"A neglected scalp infection shows yellow cup-shaped crusts, a mousy odor, and early atrophic scarring. What is the diagnosis?","ar":"عدوى مهملة بفروة الرأس تظهر قشورًا صفراء مقعرة ورائحة مميزة وندبات ضمورية مبكرة. ما التشخيص؟"},"options":[{"letter":"A","en":"Favus","ar":"الفافوس"},{"letter":"B","en":"Black dot tinea capitis","ar":"سعفة النقاط السوداء"},{"letter":"C","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"D","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"}],"correct":"A","explanation":{"en":"Scutula, mousy odor, and cicatricial alopecia are classic features of favus.","ar":"القشور المقعرة والرائحة المميزة والصلع الندبي علامات كلاسيكية للفافوس."},"reasoning":{"en":"This combination is sufficiently distinctive to prioritize urgent systemic therapy to prevent permanent loss.","ar":"هذه المجموعة من العلامات مميزة وتستدعي علاجًا جهازيًا سريعًا لمنع الفقد الدائم."},"image":null},{"id":"Q079","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Case","difficulty":"Medium","source":"PDF p. 64","question":{"en":"A 22-kg child has confirmed T. tonsurans tinea capitis. Which daily terbinafine dose from the chapter is appropriate?","ar":"طفل وزنه 22 كجم لديه سعفة رأس مؤكدة بـ T. tonsurans. ما جرعة التيربينافين اليومية المناسبة حسب الفصل؟"},"options":[{"letter":"A","en":"125 mg daily","ar":"125 مجم يوميًا"},{"letter":"B","en":"62.5 mg daily","ar":"62.5 مجم يوميًا"},{"letter":"C","en":"250 mg twice daily","ar":"250 مجم مرتين يوميًا"},{"letter":"D","en":"500 mg daily","ar":"500 مجم يوميًا"}],"correct":"A","explanation":{"en":"The weight-based regimen listed is 62.5 mg for <20 kg, 125 mg for 20–40 kg, and 250 mg for >40 kg.","ar":"النظام المذكور حسب الوزن هو 62.5 مجم لأقل من 20 كجم، و125 مجم لوزن 20–40 كجم، و250 مجم لأكثر من 40 كجم."},"reasoning":{"en":"The child falls squarely in the 20–40 kg dosing band.","ar":"يقع وزن الطفل بوضوح ضمن فئة 20–40 كجم."},"image":null},{"id":"Q080","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Case","difficulty":"Medium","source":"PDF p. 64","question":{"en":"A young infant has confirmed tinea capitis and requires a liquid systemic antifungal. Which option is preferred in the chapter?","ar":"رضيع صغير لديه سعفة رأس مؤكدة ويحتاج مضادًا فطريًا جهازيًا سائلًا. أي خيار مفضل في الفصل؟"},"options":[{"letter":"A","en":"Fluconazole","ar":"فلوكونازول"},{"letter":"B","en":"Topical nystatin alone","ar":"نيستاتين موضعي وحده"},{"letter":"C","en":"Oral ketoconazole","ar":"كيتوكونازول فموي"},{"letter":"D","en":"Selenium shampoo alone","ar":"شامبو سيلينيوم وحده"}],"correct":"A","explanation":{"en":"Fluconazole is listed as a preferred, well-studied option in infants and is available in liquid formulation.","ar":"الفلوكونازول مذكور كخيار مفضل ومدروس جيدًا للرضع ويتوفر في صورة سائلة."},"reasoning":{"en":"Age, formulation needs, and systemic penetration guide the selection.","ar":"العمر والحاجة إلى صورة سائلة والاختراق الجهازي هي عوامل الاختيار."},"image":null},{"id":"Q081","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Case","difficulty":"Hard","source":"PDF p. 63","question":{"en":"A child with kerion is treated late and develops shiny atrophic patches with permanent loss of hair follicles. What complication occurred?","ar":"عولج طفل مصاب بكيريون متأخرًا وظهرت مناطق لامعة ضامرة مع فقد دائم لجريبات الشعر. ما المضاعفة؟"},"options":[{"letter":"A","en":"Cicatricial alopecia","ar":"الصلع الندبي"},{"letter":"B","en":"Temporary telogen effluvium","ar":"تساقط تيلوجيني مؤقت"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Postinflammatory scale only","ar":"قشور ما بعد الالتهاب فقط"}],"correct":"A","explanation":{"en":"Severe inflammatory tinea capitis can destroy follicles and cause permanent scarring alopecia.","ar":"قد تدمر سعفة الرأس الالتهابية الشديدة الجريبات وتسبب صلعًا ندبيًا دائمًا."},"reasoning":{"en":"Follicular destruction and atrophy indicate irreversible scarring rather than temporary shedding.","ar":"تدمير الجريبات والضمور يشيران إلى ندبة غير عكوسة وليس تساقطًا مؤقتًا."},"image":null},{"id":"Q082","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Treatment","difficulty":"Hard","source":"PDF p. 63","question":{"en":"Tinea capitis is strongly suspected clinically, but fungal culture will take weeks. What should be done?","ar":"يُشتبه بقوة في سعفة الرأس سريريًا لكن المزرعة ستستغرق أسابيع. ماذا يجب فعله؟"},"options":[{"letter":"A","en":"Start oral antifungal therapy promptly after appropriate sampling","ar":"بدء العلاج الفموي سريعًا بعد أخذ العينات المناسبة"},{"letter":"B","en":"Wait for culture before any treatment","ar":"انتظار المزرعة قبل أي علاج"},{"letter":"C","en":"Use topical steroid alone","ar":"استخدام كورتيزون موضعي وحده"},{"letter":"D","en":"Shave the scalp and give no drug","ar":"حلاقة الرأس دون دواء"}],"correct":"A","explanation":{"en":"Treatment should not be delayed when suspicion is strong because delay increases transmission, progression, and scarring risk.","ar":"لا ينبغي تأخير العلاج عند الاشتباه القوي لأن التأخير يزيد الانتقال والتقدم وخطر الندبات."},"reasoning":{"en":"Sampling preserves diagnostic information while early therapy protects follicles and contacts.","ar":"أخذ العينة يحفظ المعلومات التشخيصية بينما يحمي العلاج المبكر الجريبات والمخالطين."},"image":null},{"id":"Q083","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Treatment","difficulty":"Medium","source":"PDF p. 64","question":{"en":"A child has confirmed Microsporum canis tinea capitis. Which systemic agent is preferred?","ar":"طفل لديه سعفة رأس مؤكدة بـ Microsporum canis. أي دواء جهازي مفضل؟"},"options":[{"letter":"A","en":"Griseofulvin","ar":"جريزوفولفين"},{"letter":"B","en":"Nystatin","ar":"نيستاتين"},{"letter":"C","en":"Selenium sulfide alone","ar":"سيلينيوم سلفايد وحده"},{"letter":"D","en":"Topical clotrimazole alone","ar":"كلوتريمازول موضعي وحده"}],"correct":"A","explanation":{"en":"Griseofulvin generally performs better against Microsporum species than terbinafine.","ar":"يؤدي الجريزوفولفين عادةً بصورة أفضل ضد أنواع Microsporum مقارنة بالتيربينافين."},"reasoning":{"en":"Species-directed choice improves the probability of cure.","ar":"اختيار الدواء وفق النوع يزيد احتمال الشفاء."},"image":null},{"id":"Q084","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Treatment","difficulty":"Hard","source":"PDF p. 64","question":{"en":"A child with severe kerion has marked inflammation despite starting oral antifungal therapy. Which adjunct may be considered according to the chapter?","ar":"طفل لديه كيريون شديد والتهاب واضح رغم بدء مضاد فطري فموي. أي علاج مساعد يمكن التفكير فيه حسب الفصل؟"},"options":[{"letter":"A","en":"A short course of oral prednisone","ar":"دورة قصيرة من البريدنيزون الفموي"},{"letter":"B","en":"Long-term potent topical steroid monotherapy","ar":"كورتيزون موضعي قوي وحده طويلًا"},{"letter":"C","en":"No antifungal therapy","ar":"عدم استخدام مضاد فطري"},{"letter":"D","en":"Oral antibiotics in every case regardless of findings","ar":"مضاد حيوي فموي في كل الحالات دون اعتبار للعلامات"}],"correct":"A","explanation":{"en":"For severe kerion inflammation, a brief systemic corticosteroid course may be considered as an adjunct, never as a replacement for antifungal therapy.","ar":"في التهاب الكيريون الشديد يمكن التفكير في دورة قصيرة من كورتيزون جهازي كعلاج مساعد لا كبديل للمضاد الفطري."},"reasoning":{"en":"The goal is to limit inflammatory follicular damage while continuing etiologic treatment.","ar":"الهدف هو تقليل ضرر الجريبات الالتهابي مع استمرار علاج السبب."},"image":null},{"id":"Q085","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Treatment","difficulty":"Hard","source":"PDF p. 64","question":{"en":"Which household advice is most appropriate after diagnosing tinea capitis in a child?","ar":"ما النصيحة المنزلية الأنسب بعد تشخيص سعفة الرأس لدى طفل؟"},"options":[{"letter":"A","en":"Screen contacts and pets, avoid sharing combs/hats, and clean bedding","ar":"فحص المخالطين والحيوانات وتجنب مشاركة الأمشاط والقبعات وتنظيف الفراش"},{"letter":"B","en":"Exclude the child from school for the entire treatment course","ar":"منع الطفل من المدرسة طوال فترة العلاج"},{"letter":"C","en":"Share hair tools after rinsing with water","ar":"مشاركة أدوات الشعر بعد شطفها بالماء"},{"letter":"D","en":"Treat only visible scalp lesions topically","ar":"علاج الآفات الظاهرة موضعيًا فقط"}],"correct":"A","explanation":{"en":"Reservoirs and fomites can sustain transmission; children can generally return to school after effective treatment begins.","ar":"قد تحافظ المستودعات والأدوات الملوثة على الانتقال، ويمكن للطفل عادةً العودة للمدرسة بعد بدء العلاج الفعال."},"reasoning":{"en":"Control measures should interrupt transmission without unnecessary prolonged exclusion.","ar":"يجب أن تقطع الإجراءات سلسلة الانتقال دون عزل طويل غير ضروري."},"image":null},{"id":"Q086","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Image","difficulty":"Hard","source":"PDF p. 65","question":{"en":"The image shows a scaly alopecic patch with broken hairs but little inflammation. Which form is shown?","ar":"توضح الصورة بقعة متقشرة مع فقد شعر وشعيرات مكسورة والتهاب بسيط. أي شكل هو؟"},"options":[{"letter":"A","en":"Scaly tinea capitis","ar":"سعفة الرأس المتقشرة"},{"letter":"B","en":"Kerion","ar":"الكيريون"},{"letter":"C","en":"Favus","ar":"الفافوس"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"A dry scaly alopecic patch with brittle hairs is typical of the noninflammatory scaly form.","ar":"البقعة الجافة المتقشرة مع فقد الشعر وهشاشته نموذجية للشكل المتقشر غير الالتهابي."},"reasoning":{"en":"The lack of boggy swelling argues against kerion.","ar":"غياب التورم الإسفنجي يستبعد الكيريون."},"image":"assets/images/chapters/fungal/fungal-q086.webp"},{"id":"Q087","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Image","difficulty":"Medium","source":"PDF p. 65","question":{"en":"The image shows numerous dark follicular dots where hairs have broken at scalp level. What is the diagnosis?","ar":"توضح الصورة نقاطًا جريبية داكنة متعددة حيث تكسر الشعر عند مستوى الفروة. ما التشخيص؟"},"options":[{"letter":"A","en":"Black dot tinea capitis","ar":"سعفة الرأس بنمط النقاط السوداء"},{"letter":"B","en":"Favus","ar":"الفافوس"},{"letter":"C","en":"Alopecia areata","ar":"الثعلبة البقعية"},{"letter":"D","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"}],"correct":"A","explanation":{"en":"The retained dark hair stubs create the characteristic black-dot appearance.","ar":"تكوّن بقايا الشعر الداكنة الملتصقة المظهر المميز للنقاط السوداء."},"reasoning":{"en":"Follicular dots plus scale support fungal breakage rather than smooth nonscarring alopecia.","ar":"النقاط الجريبية مع القشور تدعم تكسرًا فطريًا لا ثعلبة ملساء."},"image":"assets/images/chapters/fungal/fungal-q087.webp"},{"id":"Q088","topic":"tinea-capitis","topicEn":"Tinea Capitis","topicAr":"سعفة الرأس","type":"Image","difficulty":"Hard","source":"PDF p. 65","question":{"en":"The image shows a boggy inflammatory scalp plaque with crusting and hair loss. Which diagnosis is most likely?","ar":"توضح الصورة لويحة إسفنجية التهابية بفروة الرأس مع قشور وفقد شعر. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Kerion","ar":"الكيريون"},{"letter":"B","en":"Simple dandruff","ar":"قشرة الرأس البسيطة"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Onychomycosis","ar":"فطار الأظافر"}],"correct":"A","explanation":{"en":"The swollen inflammatory plaque with alopecia is typical of kerion and requires prompt systemic treatment.","ar":"اللويحة المتورمة الملتهبة مع فقد الشعر نموذجية للكيريون وتحتاج علاجًا جهازيًا سريعًا."},"reasoning":{"en":"The image shows a deep inflammatory reaction rather than simple superficial scale.","ar":"تظهر الصورة استجابة التهابية عميقة وليس مجرد قشور سطحية."},"image":"assets/images/chapters/fungal/fungal-q088.webp"},{"id":"Q089","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"MCQ","difficulty":"Hard","source":"PDF p. 66","question":{"en":"What causes the atypical appearance of tinea incognito?","ar":"ما سبب المظهر غير النمطي للسعفة المتخفية؟"},"options":[{"letter":"A","en":"Inappropriate corticosteroid or immunosuppressive use","ar":"الاستخدام غير المناسب للكورتيزون أو مثبطات المناعة"},{"letter":"B","en":"Excess antifungal shampoo","ar":"زيادة استخدام الشامبو المضاد للفطريات"},{"letter":"C","en":"Vitamin C deficiency","ar":"نقص فيتامين ج"},{"letter":"D","en":"Bacterial vaccination","ar":"التطعيم البكتيري"}],"correct":"A","explanation":{"en":"Steroids suppress the local inflammatory response and allow dermatophytes to spread with reduced scale and altered borders.","ar":"يثبط الكورتيزون الاستجابة الالتهابية الموضعية ويسمح للفطريات الجلدية بالانتشار مع قشور أقل وحدود متغيرة."},"reasoning":{"en":"The appearance changes because host response is suppressed, not because the fungus becomes harmless.","ar":"يتغير المظهر بسبب تثبيط استجابة العائل وليس لأن الفطر أصبح غير ضار."},"image":null},{"id":"Q090","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"MCQ","difficulty":"Easy","source":"PDF p. 66","question":{"en":"Which presentation is most consistent with tinea incognito?","ar":"أي مظهر يتوافق أكثر مع السعفة المتخفية؟"},"options":[{"letter":"A","en":"Ill-defined enlarging plaques with reduced scale after steroid use","ar":"لويحات متسعة غير واضحة الحدود وقليلة القشور بعد استخدام الكورتيزون"},{"letter":"B","en":"Perfectly annular plaque that cures with steroid alone","ar":"لويحة حلقية مثالية تشفى بالكورتيزون وحده"},{"letter":"C","en":"Fixed black palmar macule without scale","ar":"بقعة سوداء ثابتة براحة اليد بلا قشور"},{"letter":"D","en":"White oral plaques that scrape off","ar":"لويحات فموية بيضاء قابلة للكشط"}],"correct":"A","explanation":{"en":"Steroid-modified tinea often loses the classic active edge and may develop pustules or follicular papules while spreading.","ar":"تفقد السعفة المعدلة بالكورتيزون الحافة النشطة الكلاسيكية وقد تظهر بثور أو حطاطات جريبية مع الانتشار."},"reasoning":{"en":"Atypical morphology plus a steroid history is the diagnostic pairing.","ar":"المظهر غير النمطي مع تاريخ الكورتيزون هو الاقتران التشخيصي المهم."},"image":null},{"id":"Q091","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"MCQ","difficulty":"Medium","source":"PDF p. 67","question":{"en":"What typically happens after the corticosteroid is stopped in tinea incognito?","ar":"ماذا يحدث عادةً بعد إيقاف الكورتيزون في السعفة المتخفية؟"},"options":[{"letter":"A","en":"Rapid inflammatory relapse or worsening","ar":"انتكاس التهابي سريع أو تدهور"},{"letter":"B","en":"Immediate permanent cure","ar":"شفاء دائم فوري"},{"letter":"C","en":"Complete loss of fungal elements","ar":"اختفاء كامل للعناصر الفطرية"},{"letter":"D","en":"Development of bacterial immunity","ar":"تكوين مناعة بكتيرية"}],"correct":"A","explanation":{"en":"The suppressed immune response rebounds after withdrawal while the untreated fungal burden remains.","ar":"ترتد الاستجابة المناعية بعد الإيقاف بينما تبقى الحمولة الفطرية دون علاج."},"reasoning":{"en":"The cycle of temporary relief and rapid relapse is a classic historical clue.","ar":"دورة التحسن المؤقت ثم الانتكاس السريع دليل تاريخي كلاسيكي."},"image":null},{"id":"Q092","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"MCQ","difficulty":"Easy","source":"PDF p. 68","question":{"en":"Which investigation is most useful to confirm suspected tinea incognito?","ar":"أي فحص هو الأكثر فائدة لتأكيد الاشتباه في السعفة المتخفية؟"},"options":[{"letter":"A","en":"KOH examination of skin scrapings","ar":"فحص KOH لكشط الجلد"},{"letter":"B","en":"Serum troponin","ar":"تروبونين المصل"},{"letter":"C","en":"Urine culture","ar":"مزرعة بول"},{"letter":"D","en":"Patch test only","ar":"اختبار رقعة فقط"}],"correct":"A","explanation":{"en":"Direct microscopy can demonstrate fungal hyphae despite the altered clinical appearance.","ar":"يمكن للفحص المباشر إظهار الخيوط الفطرية رغم تغير المظهر السريري."},"reasoning":{"en":"When morphology is unreliable due to steroids, objective demonstration of fungus is essential.","ar":"عندما يصبح الشكل غير موثوق بسبب الكورتيزون، يكون إثبات الفطر موضوعيًا ضروريًا."},"image":null},{"id":"Q093","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Case","difficulty":"Easy","source":"PDF p. 67","question":{"en":"A chronic facial rash repeatedly improves within days of a potent steroid, then returns larger and more pustular after stopping. What is most likely?","ar":"طفح مزمن بالوجه يتحسن خلال أيام مع كورتيزون قوي ثم يعود أكبر وأكثر بثورًا بعد الإيقاف. ما الأرجح؟"},"options":[{"letter":"A","en":"Tinea incognito","ar":"السعفة المتخفية"},{"letter":"B","en":"Permanent steroid-responsive eczema","ar":"إكزيما مستجيبة للكورتيزون بشكل دائم"},{"letter":"C","en":"Vitiligo","ar":"البهاق"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"Temporary steroid response followed by aggressive recurrence is characteristic of masked dermatophyte infection.","ar":"التحسن المؤقت بالكورتيزون ثم العودة بشكل أشد يميز العدوى الفطرية الجلدية المقنعة."},"reasoning":{"en":"The time course is more informative than the current atypical morphology.","ar":"التسلسل الزمني أكثر إفادة من الشكل الحالي غير النمطي."},"image":null},{"id":"Q094","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Case","difficulty":"Medium","source":"PDF p. 67","question":{"en":"A child with a groin rash has used an over-the-counter triple cream for weeks. The lesion is now extensive, thin, and poorly demarcated. What history element is most diagnostic?","ar":"طفل لديه طفح بالأربية استخدم كريمًا ثلاثيًا دون وصفة لأسابيع، وأصبحت الآفة واسعة ورقيقة وغير محددة. ما عنصر التاريخ الأكثر تشخيصًا؟"},"options":[{"letter":"A","en":"Repeated exposure to a steroid-containing combination cream","ar":"التعرض المتكرر لكريم مركب يحتوي كورتيزون"},{"letter":"B","en":"Eating dairy products","ar":"تناول منتجات الألبان"},{"letter":"C","en":"Recent vaccination","ar":"تطعيم حديث"},{"letter":"D","en":"Swimming once","ar":"السباحة مرة واحدة"}],"correct":"A","explanation":{"en":"Combination creams can mask dermatophyte infection and promote tinea incognito, especially in thin-skinned areas and children.","ar":"قد تخفي الكريمات المركبة العدوى الفطرية وتدعم السعفة المتخفية خاصة في المناطق الرقيقة والأطفال."},"reasoning":{"en":"Medication history explains both altered morphology and progressive spread.","ar":"تاريخ الدواء يفسر تغير الشكل واستمرار الانتشار معًا."},"image":null},{"id":"Q095","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Case","difficulty":"Medium","source":"PDF p. 68","question":{"en":"A steroid-modified plaque has a negative initial KOH, but suspicion remains high. What is the best next step?","ar":"لويحة معدلة بالكورتيزون أعطت KOH سلبيًا أوليًا لكن الاشتباه ما زال قويًا. ما الخطوة الأفضل؟"},"options":[{"letter":"A","en":"Repeat sampling from the active edge and consider fungal culture","ar":"إعادة أخذ عينة من الحافة النشطة والنظر في المزرعة الفطرية"},{"letter":"B","en":"Declare fungal disease impossible","ar":"اعتبار المرض الفطري مستحيلًا"},{"letter":"C","en":"Escalate steroid potency immediately","ar":"زيادة قوة الكورتيزون فورًا"},{"letter":"D","en":"Start long-term antibiotics","ar":"بدء مضاد حيوي طويل المدى"}],"correct":"A","explanation":{"en":"Sampling error is possible, particularly in altered lesions; culture or repeat microscopy can confirm the diagnosis.","ar":"قد يحدث خطأ في أخذ العينة خاصة في الآفات المتغيرة، ويمكن للمزرعة أو إعادة الفحص تأكيد التشخيص."},"reasoning":{"en":"A single negative test does not outweigh a strong exposure history and compatible course.","ar":"اختبار سلبي واحد لا يفوق تاريخ تعرض قوي ومسارًا متوافقًا."},"image":null},{"id":"Q096","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Case","difficulty":"Hard","source":"PDF p. 68","question":{"en":"A patient stops a steroid and develops severe rebound inflammation over a confirmed widespread dermatophyte infection. Which principle is correct?","ar":"أوقف مريض الكورتيزون وحدث التهاب ارتدادي شديد فوق عدوى فطرية جلدية واسعة مؤكدة. أي مبدأ صحيح؟"},"options":[{"letter":"A","en":"Treat the fungus systemically; a brief mild anti-inflammatory course may be considered only as an adjunct","ar":"علاج الفطر جهازيًا ويمكن التفكير في علاج مضاد للالتهاب قصير وخفيف كمساعد فقط"},{"letter":"B","en":"Restart prolonged potent steroid alone","ar":"إعادة كورتيزون قوي طويل وحده"},{"letter":"C","en":"Avoid antifungals until inflammation disappears","ar":"تجنب المضادات الفطرية حتى يختفي الالتهاب"},{"letter":"D","en":"Use nystatin for all dermatophytes","ar":"استخدام نيستاتين لكل الفطريات الجلدية"}],"correct":"A","explanation":{"en":"Etiologic antifungal therapy is central; anti-inflammatory treatment must not replace it or recreate immunosuppression.","ar":"العلاج المضاد للفطر هو الأساس، ولا يجب أن يستبدله العلاج المضاد للالتهاب أو يعيد تثبيط المناعة."},"reasoning":{"en":"Control the cause first while using any anti-inflammatory support cautiously and briefly.","ar":"يجب السيطرة على السبب أولًا مع استخدام الدعم المضاد للالتهاب بحذر ولفترة قصيرة."},"image":null},{"id":"Q097","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Treatment","difficulty":"Hard","source":"PDF p. 68","question":{"en":"What is the first management step in tinea incognito?","ar":"ما أول خطوة في علاج السعفة المتخفية؟"},"options":[{"letter":"A","en":"Stop the inappropriate corticosteroid","ar":"إيقاف الكورتيزون غير المناسب"},{"letter":"B","en":"Increase steroid frequency","ar":"زيادة تكرار الكورتيزون"},{"letter":"C","en":"Begin antibacterial therapy only","ar":"بدء مضاد بكتيري فقط"},{"letter":"D","en":"Occlude the lesion","ar":"تغطية الآفة بإحكام"}],"correct":"A","explanation":{"en":"Removing the factor masking the infection is essential, followed by appropriate antifungal therapy.","ar":"إزالة العامل الذي يخفي العدوى خطوة أساسية، يليها علاج مضاد للفطريات مناسب."},"reasoning":{"en":"Continuing immunosuppression undermines any attempt to eradicate the organism.","ar":"استمرار تثبيط المناعة يقوض محاولة القضاء على الكائن."},"image":null},{"id":"Q098","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Treatment","difficulty":"Medium","source":"PDF p. 68","question":{"en":"A localized tinea incognito lesion is confirmed after steroid cessation. What is an appropriate treatment?","ar":"تم تأكيد آفة موضعية من السعفة المتخفية بعد إيقاف الكورتيزون. ما العلاج المناسب؟"},"options":[{"letter":"A","en":"Topical terbinafine or clotrimazole","ar":"تيربينافين أو كلوتريمازول موضعي"},{"letter":"B","en":"Topical steroid alone","ar":"كورتيزون موضعي وحده"},{"letter":"C","en":"Oral antibiotic alone","ar":"مضاد حيوي فموي وحده"},{"letter":"D","en":"No treatment because scaling is reduced","ar":"لا علاج لأن القشور قليلة"}],"correct":"A","explanation":{"en":"Localized disease can be treated with an appropriate topical dermatophyte-active agent.","ar":"يمكن علاج المرض الموضعي بمضاد فطري موضعي فعال ضد الفطريات الجلدية."},"reasoning":{"en":"Reduced scale does not mean reduced fungal burden after steroid use.","ar":"قلة القشور لا تعني قلة الحمولة الفطرية بعد الكورتيزون."},"image":null},{"id":"Q099","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Treatment","difficulty":"Medium","source":"PDF p. 68","question":{"en":"When should systemic therapy be considered for tinea incognito?","ar":"متى يجب التفكير في العلاج الجهازي للسعفة المتخفية؟"},"options":[{"letter":"A","en":"When disease is widespread, deep, resistant, or involves difficult sites","ar":"عندما يكون المرض واسعًا أو عميقًا أو مقاومًا أو في مواقع صعبة"},{"letter":"B","en":"For every single small lesion","ar":"لكل آفة صغيرة منفردة"},{"letter":"C","en":"Only when KOH is negative","ar":"فقط عندما يكون KOH سلبيًا"},{"letter":"D","en":"Never, because steroids cured it","ar":"أبدًا لأن الكورتيزون شفاه"}],"correct":"A","explanation":{"en":"Systemic terbinafine, itraconazole, fluconazole, or griseofulvin may be required according to site and organism.","ar":"قد يلزم تيربينافين أو إيتراكونازول أو فلوكونازول أو جريزوفولفين جهازيًا حسب الموقع والكائن."},"reasoning":{"en":"Extent and penetration needs determine escalation beyond topical therapy.","ar":"الانتشار والحاجة إلى الاختراق يحددان التصعيد إلى علاج يتجاوز الموضعي."},"image":null},{"id":"Q100","topic":"tinea-incognito","topicEn":"Tinea Incognito","topicAr":"السعفة المتخفية","type":"Image","difficulty":"Medium","source":"PDF p. 67","question":{"en":"The image shows an extensive, irregular, poorly demarcated inflammatory plaque after repeated steroid use. Which diagnosis is most likely?","ar":"توضح الصورة لويحة التهابية واسعة وغير منتظمة وغير واضحة الحدود بعد استخدام متكرر للكورتيزون. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Tinea incognito","ar":"السعفة المتخفية"},{"letter":"B","en":"Classic untreated tinea with a perfect ring","ar":"سعفة كلاسيكية غير معالجة بحلقة مثالية"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Oral candidiasis","ar":"داء المبيضات الفموي"}],"correct":"A","explanation":{"en":"Steroid exposure can erase the classic ring and produce diffuse atypical inflammation with continued fungal spread.","ar":"قد يمحو الكورتيزون الحلقة الكلاسيكية ويسبب التهابًا منتشرًا غير نمطي مع استمرار انتشار الفطر."},"reasoning":{"en":"The medication history explains why the image lacks a typical active border.","ar":"يفسر تاريخ الدواء غياب الحافة النشطة المعتادة في الصورة."},"image":"assets/images/chapters/fungal/fungal-q100.webp"}]);
